// The typical-radiation-dose dataset, loaded onto the curated-dataset framework
// (issue #703, #860). Copies the ototoxic.ts / contrast-safety.ts shape: import the
// envelope JSON (generated by scripts/gen-radiation-dose.ts), validate it once with
// loadDataset(), and expose the per-exam typical-dose entries + the natural-background
// comparator (in `meta`) the domain fallback consumes. Identity is the exam `key` slug
// (fieldStrategy "key"). The registry lists this for the linter; lib/radiation-dose.ts
// is the DOMAIN estimator + trailing-window cumulative. Pure — no DB, no network.

import rawRadiationDose from "./data/radiation-dose.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type {
  RadiationDoseEntry,
  RadiationDoseMeta,
} from "@/scripts/gen-radiation-dose";

export type {
  RadiationDoseEntry,
  RadiationDoseMeta,
} from "@/scripts/gen-radiation-dose";

// The validated dataset (envelope + guarantees). Throws at module load if the
// committed JSON ever violates the contract — a loud, early failure.
export const radiationDoseDataset = loadDataset<
  RadiationDoseEntry,
  RadiationDoseMeta
>(rawRadiationDose);

// Identity strategy: the exam `key` slug, case-folded. For the linter.
export const radiationDoseKeyStrategy = fieldStrategy("key");

// The typical-dose entries the estimator consumes.
export const RADIATION_DOSE_ENTRIES: RadiationDoseEntry[] =
  radiationDoseDataset.entries;

// The natural-background comparator (US average annual effective dose, ~3 mSv/yr) —
// used ONLY to phrase the running total in calm, relatable terms, never as a threshold.
export const RADIATION_DOSE_META: RadiationDoseMeta =
  radiationDoseDataset.meta as RadiationDoseMeta;
